1	import type { QueuedAttempt } from '$lib/types/notifications';
2	import { QueuedAttemptStatus } from '$lib/types/enums';
3	import { NOTIFICATION_RETRY_DELAYS, MAX_NOTIFICATION_RETRIES } from '$lib/constants';
4	
5	export function getNextRetryTimestamp(
6	  currentAttemptNumber: number,
7	  processedAt: string,
8	): string | null {
9	  const delayIndex = currentAttemptNumber - 1;
10	  if (delayIndex < 0 || delayIndex >= NOTIFICATION_RETRY_DELAYS.length) {
11	    return null;
12	  }
13	  const delayMs = NOTIFICATION_RETRY_DELAYS[delayIndex];
14	  return new Date(new Date(processedAt).getTime() + delayMs).toISOString();
15	}
16	
17	export function getOverdueAttempts(
18	  attempts: QueuedAttempt[],
19	  now: Date = new Date(),
20	): QueuedAttempt[] {
21	  return attempts.filter(
22	    a =>
23	      a.status === QueuedAttemptStatus.Pending &&
24	      new Date(a.scheduledAt).getTime() <= now.getTime(),
25	  );
26	}
27	
28	export function isMaxRetriesReached(attemptNumber: number): boolean {
29	  return attemptNumber > MAX_NOTIFICATION_RETRIES;
30	}
