18	  attempts: QueuedAttempt[],
19	  now: Date = new Date(),
20	): QueuedAttempt[] {
21	  return attempts.filter(
22	    a =>
23	      a.status === QueuedAttemptStatus.Pending &&
24	      new Date(a.scheduledAt).getTime() <= now.getTime(),
25	  );
26	}
