42	export async function markAsRead(
43	  notificationId: string,
44	  userId: string,
45	): Promise<ReadReceipt> {
46	  const notif = await notifRepo.getById(notificationId);
47	  if (notif && !notif.readAt) {
48	    await notifRepo.put({ ...notif, readAt: new Date().toISOString() });
49	  }
50	
51	  const now = new Date().toISOString();
52	  const receipt: ReadReceipt = {
53	    id: crypto.randomUUID(),
54	    notificationId,
55	    userId,
56	    readAt: now,
57	    createdAt: now,
58	    updatedAt: now,
59	    version: 1,
60	  };
61	  await receiptRepo.add(receipt);
62	  return receipt;
63	}
64	
65	export async function queueExternalAttempt(
66	  notificationId: string,
67	  channel: NotificationChannel,
68	  templateId: string,
69	): Promise<QueuedAttempt> {
70	  const now = new Date().toISOString();
71	  const attempt: QueuedAttempt = {
72	    id: crypto.randomUUID(),
73	    notificationId,
74	    channel,
75	    templateId,
76	    attemptNumber: 1,
77	    scheduledAt: now,
78	    status: QueuedAttemptStatus.Pending,
79	    createdAt: now,
80	    updatedAt: now,
81	    version: 1,
82	  };
83	  await attemptRepo.add(attempt);
84	  logger.info('External attempt queued', { notificationId, channel });
85	  return attempt;
86	}
87	
88	export async function processRetries(now: Date = new Date()): Promise<{
89	  processed: number;
90	  scheduledNext: number;
91	  skipped: number;
92	}> {
93	  const allPending = await attemptRepo.getPending();
94	  const overdue = getOverdueAttempts(allPending, now);
95	
96	  let processed = 0;
97	  let scheduledNext = 0;
98	  let skipped = 0;
99	
100	  for (const attempt of overdue) {
101	    // Simulate the attempt (external channels are audit-only)
102	    await attemptRepo.put({
103	      ...attempt,
104	      status: QueuedAttemptStatus.Simulated,
105	      processedAt: now.toISOString(),
106	      updatedAt: now.toISOString(),
107	    });
108	    processed++;
109	
110	    // Schedule next retry or mark as complete
111	    const nextTimestamp = getNextRetryTimestamp(attempt.attemptNumber, now.toISOString());
112	    if (nextTimestamp && !isMaxRetriesReached(attempt.attemptNumber + 1)) {
113	      const nextAttempt: QueuedAttempt = {
114	        id: crypto.randomUUID(),
115	        notificationId: attempt.notificationId,
116	        channel: attempt.channel,
117	        templateId: attempt.templateId,
118	        attemptNumber: attempt.attemptNumber + 1,
119	        scheduledAt: nextTimestamp,
120	        status: QueuedAttemptStatus.Pending,
121	        createdAt: now.toISOString(),
122	        updatedAt: now.toISOString(),
123	        version: 1,
124	      };
125	      await attemptRepo.add(nextAttempt);
126	      scheduledNext++;
127	    } else {
128	      skipped++;
129	    }
130	  }
131	
132	  if (processed > 0) {
133	    logger.info('Retries processed', { processed, scheduledNext, skipped });
134	  }
135	  return { processed, scheduledNext, skipped };
136	}
137	
138	export async function getInbox(userId: string): Promise<Notification[]> {
139	  return notifRepo.getByUser(userId);
140	}
141	
142	export async function getUnread(userId: string): Promise<Notification[]> {
143	  return notifRepo.getUnread(userId);
144	}
145	
146	export async function getAttemptLog(notificationId?: string): Promise<QueuedAttempt[]> {
147	  if (notificationId) {
148	    return attemptRepo.getByNotification(notificationId);
149	  }
150	  return attemptRepo.getAll();
151	}
152	
153	/**
154	 * Centralized notification dispatch: creates inbox item AND queues
155	 * external-channel attempts for any non-inbox subscribed channels.
156	 * This is the single entry point business events should use.
157	 */
158	export async function dispatchNotification(
159	  userId: string,
160	  eventType: NotificationType,
161	  title: string,
162	  body: string,
163	  data?: Record<string, unknown>,
164	): Promise<{ notification: Notification; queuedAttempts: QueuedAttempt[] }> {
165	  // 1. Always create inbox item
166	  const notification = await createInboxItem(userId, eventType, title, body, data);
167	
168	  // 2. Check user subscriptions for non-inbox channels
169	  const queuedAttempts: QueuedAttempt[] = [];
170	  try {
171	    const subscriptions = await getSubscriptions(userId);
172	    const sub = subscriptions.find(s => s.eventType === eventType && s.enabled);
173	    const channels = sub?.channels ?? [NotificationChannel.Inbox];
174	
175	    for (const channel of channels) {
176	      if (channel === NotificationChannel.Inbox) continue; // already handled above
177	
178	      // Find template for this event+channel
179	      const template = await getTemplateByEvent(eventType, channel);
180	      if (template) {
181	        const attempt = await queueExternalAttempt(notification.id, channel, template.id);
182	        queuedAttempts.push(attempt);
183	      }
184	    }
185	  } catch (e) {
186	    // Subscription/queue failures should not block the primary notification
187	    logger.warn('Failed to queue external attempts', { eventType, error: (e as Error).message });
188	  }
189	
190	  if (queuedAttempts.length > 0) {
191	    logger.info('External attempts queued', { notificationId: notification.id, channels: queuedAttempts.map(a => a.channel) });
192	  }
193	
194	  return { notification, queuedAttempts };
195	}
