18	export async function planWave(
19	  orderIds: string[],
20	  config?: Partial<WaveConfig>,
21	): Promise<Wave> {
22	  if (!getCurrentSession()) {
23	    throw new ValidationServiceError('Not authenticated', [
24	      { field: 'session', message: 'User must be logged in', code: 'unauthenticated' },
25	    ]);
26	  }
