28	  const waveConfig: WaveConfig = {
29	    maxLinesPerWave: config?.maxLinesPerWave ?? WAVE_DEFAULT_SIZE,
30	    priorityRules: config?.priorityRules,
31	  };
32	
33	  const validation = validateWaveConfig(waveConfig);
34	  if (!validation.valid) throw new ValidationServiceError('Invalid wave config', validation.errors);
35	
36	  const orders: Order[] = [];
37	  let totalLines = 0;
38	
39	  for (const orderId of orderIds) {
40	    const order = await orderRepo.getById(orderId);
41	    if (!order) {
42	      throw new ValidationServiceError('Order not found', [
43	        { field: 'orderIds', message: `Order ${orderId} not found`, code: 'not_found' },
44	      ]);
45	    }
46	    totalLines += order.lines.length;
47	    orders.push(order);
48	  }
49	
50	  if (totalLines > waveConfig.maxLinesPerWave) {
51	    throw new ValidationServiceError('Wave exceeds line limit', [
52	      {
53	        field: 'lines',
54	        message: `Total lines ${totalLines} exceeds max ${waveConfig.maxLinesPerWave}`,
55	        code: 'exceeds_wave_size',
56	      },
57	    ]);
58	  }
59	
60	  const now = new Date().toISOString();
61	  const wave: Wave = {
62	    id: crypto.randomUUID(),
63	    waveNumber: `WAVE-${Date.now()}`,
64	    status: WaveStatus.Planned,
65	    orderIds,
66	    lineCount: totalLines,
67	    config: waveConfig,
68	    createdAt: now,
69	    updatedAt: now,
70	    version: 1,
71	  };
72	
73	  await waveRepo.add(wave);
74	  logger.info('Wave planned', { waveId: wave.id, orderCount: orderIds.length, totalLines });
75	  return wave;
