78	export async function assignTask(
79	  waveId: string,
80	  pickerId: string,
81	  pickPathConfig: PickPathConfig,
82	): Promise<PickerTask> {
83	  const wave = await waveRepo.getById(waveId);
84	  if (!wave) {
85	    throw new ValidationServiceError('Wave not found', [
86	      { field: 'waveId', message: 'Wave does not exist', code: 'not_found' },
87	    ]);
88	  }
89	
90	  const steps: PickPathStep[] = [];
91	  for (const orderId of wave.orderIds) {
92	    const order = await orderRepo.getById(orderId);
93	    if (!order) continue;
94	    for (const line of order.lines) {
95	      if (line.binId) {
96	        // Look up real bin metadata for zone and code
97	        const bin = await binRepo.getById(line.binId);
98	        steps.push({
99	          binId: line.binId,
100	          zone: bin?.zone ?? '',
101	          binCode: bin?.code ?? line.binId,
102	          skuId: line.skuId,
103	          quantity: line.quantity,
104	          sequence: 0,
105	        });
106	      }
107	    }
108	  }
109	
110	  const sortedSteps = sortPickPath(steps, pickPathConfig);
111	
112	  const now = new Date().toISOString();
113	  const task: PickerTask = {
114	    id: crypto.randomUUID(),
115	    waveId,
116	    pickerId,
117	    status: TaskStatus.Assigned,
118	    steps: sortedSteps,
119	    assignedAt: now,
120	    createdAt: now,
121	    updatedAt: now,
122	    version: 1,
123	  };
124	
125	  await taskRepo.add(task);
126	  logger.info('Task assigned', { taskId: task.id, waveId, pickerId, stepCount: sortedSteps.length });
127	
128	  try {
129	    await dispatchNotification(pickerId, NotificationType.WaveAssigned, 'Wave Assigned',
130	      `You have been assigned to wave ${wave.waveNumber} with ${sortedSteps.length} pick steps`,
131	      { waveId, waveNumber: wave.waveNumber, stepCount: sortedSteps.length });
132	  } catch { /* notification failure should not block task assignment */ }
133	
134	  return task;
135	}
136	
137	export async function startWave(waveId: string): Promise<Wave> {
138	  const wave = await waveRepo.getById(waveId);
139	  if (!wave) throw new ValidationServiceError('Wave not found', [
140	    { field: 'waveId', message: 'Wave does not exist', code: 'not_found' },
141	  ]);
142	
143	  if (wave.status !== WaveStatus.Planned) {
144	    throw new ValidationServiceError('Wave cannot be started', [
145	      { field: 'status', message: `Wave is ${wave.status}, must be planned`, code: 'invalid_state' },
146	    ]);
147	  }
148	
149	  return waveRepo.put({
150	    ...wave,
151	    status: WaveStatus.InProgress,
152	    startedAt: new Date().toISOString(),
153	    updatedAt: new Date().toISOString(),
154	  });
155	}
156	
157	export async function completeWave(waveId: string): Promise<Wave> {
158	  const wave = await waveRepo.getById(waveId);
159	  if (!wave) throw new ValidationServiceError('Wave not found', [
160	    { field: 'waveId', message: 'Wave does not exist', code: 'not_found' },
161	  ]);
162	
163	  if (wave.status !== WaveStatus.InProgress) {
164	    throw new ValidationServiceError('Wave cannot be completed', [
165	      { field: 'status', message: `Wave is ${wave.status}, must be in_progress`, code: 'invalid_state' },
166	    ]);
167	  }
168	
169	  const tasks = await taskRepo.getByWave(waveId);
170	  const allComplete = tasks.every(t => t.status === TaskStatus.Completed);
171	  if (!allComplete) {
