6	import { getCurrentSession } from '$lib/security/auth.service';
7	import type { Discrepancy, DiscrepancyAttachment } from '$lib/types/orders';
8	
9	const discrepancyRepo = new DiscrepancyRepository();
10	const logger = createLogger('inventory');
11	
12	const VALID_TRANSITIONS: Record<DiscrepancyState, DiscrepancyState[]> = {
13	  [DiscrepancyState.Opened]: [DiscrepancyState.UnderReview],
14	  [DiscrepancyState.UnderReview]: [DiscrepancyState.Verified],
15	  [DiscrepancyState.Verified]: [DiscrepancyState.Resolved],
16	  [DiscrepancyState.Resolved]: [],
17	};
18	
19	function assertTransition(current: DiscrepancyState, target: DiscrepancyState): void {
20	  const allowed = VALID_TRANSITIONS[current];
21	  if (!allowed || !allowed.includes(target)) {
22	    throw new ValidationServiceError('Invalid state transition', [
23	      {
24	        field: 'state',
25	        message: `Cannot transition from ${current} to ${target}`,
26	        code: 'invalid_transition',
27	      },
28	    ]);
29	  }
30	}
31	
32	export async function reportDiscrepancy(
33	  taskId: string,
34	  reportedBy: string,
35	  description: string,
36	  attachments: DiscrepancyAttachment[] = [],
37	  orderId?: string,
38	): Promise<Discrepancy> {
39	  if (!description.trim()) {
40	    throw new ValidationServiceError('Description required', [
41	      { field: 'description', message: 'Description is required', code: 'required' },
42	    ]);
43	  }
44	
45	  const now = new Date().toISOString();
46	  const discrepancy: Discrepancy = {
47	    id: crypto.randomUUID(),
48	    taskId,
49	    orderId,
50	    state: DiscrepancyState.Opened,
51	    reportedBy,
52	    reportedAt: now,
53	    description,
54	    attachments,
55	    createdAt: now,
56	    updatedAt: now,
57	    version: 1,
58	  };
59	
60	  await discrepancyRepo.add(discrepancy);
61	  logger.info('Discrepancy reported', { discrepancyId: discrepancy.id, taskId });
62	
63	  try {
64	    const userId = getCurrentSession()?.userId ?? 'system';
65	    await dispatchNotification(userId, NotificationType.DiscrepancyOpened, 'Discrepancy Reported',
66	      `Discrepancy on task ${taskId}: ${description}`, { taskId, discrepancyId: discrepancy.id });
67	  } catch { /* notification failure should not block discrepancy reporting */ }
68	
69	  return discrepancy;
70	}
71	
72	export async function reviewDiscrepancy(
73	  discrepancyId: string,
74	  notes?: string,
75	): Promise<Discrepancy> {
76	  const d = await discrepancyRepo.getById(discrepancyId);
77	  if (!d) throw new ValidationServiceError('Discrepancy not found', [
78	    { field: 'discrepancyId', message: 'Not found', code: 'not_found' },
79	  ]);
80	
81	  assertTransition(d.state, DiscrepancyState.UnderReview);
82	
83	  return discrepancyRepo.put({
84	    ...d,
85	    state: DiscrepancyState.UnderReview,
86	    verificationNotes: notes ?? d.verificationNotes,
87	    updatedAt: new Date().toISOString(),
88	  });
89	}
90	
91	export async function verifyDiscrepancy(
92	  discrepancyId: string,
93	  verifiedBy: string,
94	  notes: string,
95	  attachments: DiscrepancyAttachment[] = [],
96	): Promise<Discrepancy> {
97	  const d = await discrepancyRepo.getById(discrepancyId);
98	  if (!d) throw new ValidationServiceError('Discrepancy not found', [
99	    { field: 'discrepancyId', message: 'Not found', code: 'not_found' },
100	  ]);
101	
102	  assertTransition(d.state, DiscrepancyState.Verified);
103	
104	  if (!verifiedBy) {
105	    throw new ValidationServiceError('Verifier required', [
106	      { field: 'verifiedBy', message: 'Verifier identity is required', code: 'required' },
107	    ]);
108	  }
109	
110	  const now = new Date().toISOString();
111	  return discrepancyRepo.put({
112	    ...d,
113	    state: DiscrepancyState.Verified,
114	    verifiedBy,
115	    verifiedAt: now,
116	    verificationNotes: notes,
117	    attachments: [...d.attachments, ...attachments],
118	    updatedAt: now,
119	  });
120	}
121	
122	export async function resolveDiscrepancy(discrepancyId: string): Promise<Discrepancy> {
123	  const d = await discrepancyRepo.getById(discrepancyId);
124	  if (!d) throw new ValidationServiceError('Discrepancy not found', [
125	    { field: 'discrepancyId', message: 'Not found', code: 'not_found' },
126	  ]);
127	
128	  assertTransition(d.state, DiscrepancyState.Resolved);
129	
130	  const now = new Date().toISOString();
131	  const resolved = await discrepancyRepo.put({
132	    ...d,
133	    state: DiscrepancyState.Resolved,
134	    resolvedAt: now,
135	    updatedAt: now,
136	  });
137	
138	  try {
139	    const userId = getCurrentSession()?.userId ?? 'system';
140	    await dispatchNotification(userId, NotificationType.DiscrepancyClosed, 'Discrepancy Resolved',
141	      `Discrepancy for task ${d.taskId} has been resolved`, { taskId: d.taskId, discrepancyId: d.id });
142	  } catch { /* notification failure should not block resolution */ }
143	
144	  return resolved;
145	}
