4	const { Administrator, WarehouseManager, PickerPacker, Auditor } = UserRole;
5	const ALL_ROLES = [Administrator, WarehouseManager, PickerPacker, Auditor];
6	
7	export const PERMISSION_MATRIX: Permission[] = [
8	  { capability: 'identity.reveal_basic', roles: [Administrator, WarehouseManager] },
9	  { capability: 'identity.reveal_sensitive', roles: [Administrator] },
10	  { capability: 'files.reveal_key_metadata', roles: [Administrator] },
11	  { capability: 'users.reveal_contact', roles: [Administrator] },
12	];
13	
14	export const ROUTE_ACCESS: Record<string, UserRole[]> = {
15	  '/': ALL_ROLES,
16	  '/dashboard': ALL_ROLES,
17	  '/inventory': [Administrator, WarehouseManager, Auditor],
18	  '/inventory/ledger': [Administrator, WarehouseManager, Auditor],
19	  '/orders': [Administrator, WarehouseManager, PickerPacker],
20	  '/orders/waves': [Administrator, WarehouseManager],
21	  '/files': [Administrator, WarehouseManager],
22	  '/identity': [Administrator],
23	  '/notifications': ALL_ROLES,
24	  '/settings': ALL_ROLES,
25	};
26	
27	export const MUTATION_ACCESS: Record<string, UserRole[]> = {
28	  'inventory.create': [Administrator, WarehouseManager],
29	  'inventory.update': [Administrator, WarehouseManager],
30	  'inventory.transfer': [Administrator, WarehouseManager],
31	  'inventory.count': [Administrator, WarehouseManager, PickerPacker],
32	  'orders.create': [Administrator, WarehouseManager],
33	  'orders.update': [Administrator, WarehouseManager],
34	  'orders.pick': [Administrator, WarehouseManager, PickerPacker],
35	  'orders.pack': [Administrator, WarehouseManager, PickerPacker],
36	  'waves.plan': [Administrator, WarehouseManager],
37	  'files.upload': [Administrator, WarehouseManager],
38	  'files.delete': [Administrator, WarehouseManager],
39	  'files.restore': [Administrator, WarehouseManager],
40	  'identity.enroll': [Administrator],
41	  'identity.import': [Administrator],
42	  'users.create': [Administrator],
43	  'users.update': [Administrator],
44	  'settings.update': [Administrator],
45	  'discrepancy.report': [Administrator, WarehouseManager, PickerPacker],
46	  'discrepancy.review': [Administrator, WarehouseManager],
47	  'discrepancy.resolve': [Administrator, WarehouseManager],
48	};
49	
50	export function canAccess(role: UserRole, route: string): boolean {
51	  const allowed = ROUTE_ACCESS[route];
52	  if (!allowed) return false;
53	  return allowed.includes(role);
54	}
55	
56	export function canMutate(role: UserRole, action: string): boolean {
57	  const allowed = MUTATION_ACCESS[action];
58	  if (!allowed) return false;
59	  return allowed.includes(role);
60	}
61	
62	export function canReveal(role: UserRole, capability: RevealCapability): boolean {
63	  const entry = PERMISSION_MATRIX.find(p => p.capability === capability);
64	  if (!entry) return false;
65	  return entry.roles.includes(role);
66	}
67	
68	export function isReadOnly(role: UserRole): boolean {
69	  return role === UserRole.Auditor;
70	}
