10	/**
11	 * Generate a deterministic feature vector from image data.
12	 *
13	 * DISCLOSURE: This is an on-device application feature for local identity
14	 * records. It is NOT a certified biometric verification system. The vector
15	 * is a deterministic embedding derived from pixel analysis, suitable for
16	 * local profile matching experiments within the app.
17	 */
18	export function generateVector(imageData: ImageData): Float32Array {
19	  const { width, height, data } = imageData;
20	  const vectorSize = 128;
21	  const vector = new Float32Array(vectorSize);
22	
23	  // Grid-based feature extraction: divide image into blocks
24	  const blockW = Math.floor(width / 16);
25	  const blockH = Math.floor(height / 8);
26	
27	  let vi = 0;
28	  for (let by = 0; by < 8 && vi < vectorSize; by++) {
29	    for (let bx = 0; bx < 16 && vi < vectorSize; bx++) {
30	      let sum = 0;
31	      let count = 0;
32	
33	      for (let y = by * blockH; y < (by + 1) * blockH && y < height; y++) {
34	        for (let x = bx * blockW; x < (bx + 1) * blockW && x < width; x++) {
35	          const idx = (y * width + x) * 4;
36	          sum += data[idx] * 0.299 + data[idx + 1] * 0.587 + data[idx + 2] * 0.114;
37	          count++;
38	        }
39	      }
40	
41	      vector[vi] = count > 0 ? sum / count / 255 : 0;
42	      vi++;
43	    }
44	  }
45	
46	  return vector;
47	}
