64	    status: WaveStatus.Planned,
65	    orderIds,
66	    lineCount: totalLines,
67	    config: waveConfig,
68	    createdAt: now,
69	    updatedAt: now,
70	    version: 1,
71	  };
72	
73	  await waveRepo.add(wave);
74	  logger.info('Wave planned', { waveId: wave.id, orderCount: orderIds.length, totalLines });
