81	    } else {
82	      const lines = data.split('\n').filter(l => l.trim());
83	      if (lines.length < 2) return { totalRecords: 0, importedCount: 0, skippedCount: 0, errors: [] };
84	      const headers = lines[0].split(',').map(h => h.trim());
85	      profiles = lines.slice(1).map(line => {
