51	  const validation = validateOrder(orderData);
52	  if (!validation.valid) throw new ValidationServiceError('Invalid order', validation.errors);
53	
54	  const now = new Date().toISOString();
55	  const order: Order = {
56	    id: crypto.randomUUID(),
