import { encrypt, arrayBufferToBase64, uint8ArrayToBase64 } from '$lib/security/crypto';
```

Modify `enrollProfile` to become `async` with encryption logic:

```typescript
export async function enrollProfile(
  name: string,
  groupId?: string,
  attributes: Record<string, string> = {},
): Promise<FaceProfile> {
  const dek = getCurrentDEK();
  if (!dek) {
    throw new Error('No encryption key available. User must be logged in.');
  }

  const attributesJson = JSON.stringify(attributes);
  const { ciphertext, iv } = await encrypt(attributesJson, dek);

  const now = new Date().toISOString();
  const profile: FaceProfile = {
    id: crypto.randomUUID(),
    name,
    groupId,
    attributes: {},                                     // empty at rest
    encryptedAttributes: arrayBufferToBase64(ciphertext),
    attributesIV: uint8ArrayToBase64(iv),
    enrolledBy: 'current-user',
    enrolledAt: now,
    createdAt: now,
    updatedAt: now,
    version: 1,
  };
  await profileRepo.add(profile);
  logger.info('Profile enrolled', { profileId: profile.id, name });
  return { ...profile, attributes };  // return with decrypted attributes for caller
}
```

This matches the existing pattern in `vector.service.ts` lines 49-77 where `encryptAndStore` calls `getCurrentDEK()`, checks for null, calls `encrypt()`, then stores with `arrayBufferToBase64` and `uint8ArrayToBase64`.

#### Step 3: Add `decryptProfileAttributes()` helper

**File**: `C:/Users/Hello/OneDrive/Desktop/w2t120/repo/frontend/src/modules/identity/identity.service.ts`

