```typescript
export async function decryptProfileAttributes(
  profile: FaceProfile,
): Promise<Record<string, string>> {
  if (!profile.encryptedAttributes || !profile.attributesIV) {
    // Legacy record: attributes still in plaintext
    return profile.attributes;
  }

  const dek = getCurrentDEK();
  if (!dek) {
    // DEK unavailable (locked/logged out) -- return empty
    return {};
  }

  const ciphertext = base64ToArrayBuffer(profile.encryptedAttributes);
  const iv = base64ToUint8Array(profile.attributesIV);
  const json = await decrypt(ciphertext, iv, dek);
  return JSON.parse(json);
}
```

