   ```typescript
   import type { DiscrepancyAttachment } from '$lib/types/orders';
   // (already importing Discrepancy; add DiscrepancyAttachment to the import)

   function filesToAttachments(files: FileList | null, discrepancyId: string): DiscrepancyAttachment[] {
     if (!files) return [];
     return Array.from(files).map(f => ({
       id: crypto.randomUUID(),
       discrepancyId,
       fileId: crypto.randomUUID(),  // local-only reference
       type: f.type || 'application/octet-stream',
       name: f.name,
       addedAt: new Date().toISOString(),
     }));
   }
   ```
   This creates metadata-only attachment records. Since this is a pure-offline SPA with no backend, we generate local UUIDs for both `id` and `fileId`. The actual file content is not stored (consistent with the offline IndexedDB architecture where the service layer stores the `Discrepancy` object with its `attachments` array as structured metadata).

3. **Modify `handleReport()`** (currently line 31-38):
