0	/**
1	 * Critical-path E2E smoke test
2	 *
3	 * Exercises the full happy-path flow through the service layer:
4	 *   login → create order → plan wave → assign task → report discrepancy →
5	 *   review → verify → notification dispatch evidence
6	 *
7	 * Runs in jsdom/fake-indexeddb (no real browser). This validates that all
8	 * service-layer modules compose correctly end-to-end.
9	 */
10	import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
11	import 'fake-indexeddb/auto';
12	import { initDatabase, closeDb } from '../src/lib/db/connection';
